query:
SELECT c.id, c.name FROM cities c WHERE c.name LIKE '%重庆%';

SELECT e.* FROM city_monthly_expenses e 
JOIN cities c ON e.cityId = c.id 
WHERE c.name LIKE '%重庆%' 
ORDER BY e.month DESC 
LIMIT 3;

